/* empty css                                                                  *//* empty css                                                                  */import{B as d}from"./BaseBreadcrumbs-D2EQ1GoT.js";/* empty css                                                                 *//* empty css                                                                  *//* empty css                                                                   */import{d as s,c as e,a,b as c,u as v,e as i,i as l,_ as o}from"./index-CIW3DgOy.js";const r={class:"about-view"},n={class:"page-content"},p={class:"container"},m=s({__name:"AboutView",setup(b){return(u,t)=>(l(),e("div",r,[t[1]||(t[1]=a("section",{class:"page-header"},[a("div",{class:"container"},[a("h1",{class:"hero-title"},"О компании «ГрузЭкспресс»"),a("p",{class:"hero-subtitle"},"Мы делаем грузоперевозки доступными, безопасными и удобными для каждого")])],-1)),a("section",n,[a("div",p,[c(v(d),{items:[{label:"Главная",to:"/"},{label:"О компании"}]}),t[0]||(t[0]=i('<div class="text-block" data-v-6deca830><h3 data-v-6deca830>Наша история</h3><p data-v-6deca830> Компания «ГрузЭкспресс» была основана в 2010 году в Москве группой профессионалов логистической отрасли. Начав свою деятельность с небольшого парка из 10 грузовых автомобилей, мы за более чем 13 лет выросли в одну из крупнейших транспортно-логистических компаний России. Сегодня наш автопарк насчитывает свыше 200 единиц техники различной грузоподъёмности — от малотоннажных фургонов для городских перевозок до мощных большегрузных тягачей для магистральных рейсов. </p><p data-v-6deca830> За годы работы мы заслужили доверие тысяч клиентов — от частных лиц, которым необходимо перевезти личные вещи при переезде, до крупных промышленных предприятий, требующих регулярных поставок сырья и готовой продукции. Мы гордимся тем, что 98% наших клиентов рекомендуют нас своим партнёрам и знакомым. </p></div><div class="text-block" data-v-6deca830><h3 data-v-6deca830>Наша миссия и ценности</h3><p data-v-6deca830> Миссия компании «ГрузЭкспресс» — сделать качественные грузоперевозки доступными для каждого, обеспечивая максимальную надёжность и безопасность транспортировки. Мы стремимся к тому, чтобы каждый клиент чувствовал уверенность в сохранности своего груза и получал удовольствие от сотрудничества с нами. </p><p data-v-6deca830> Наши ключевые ценности: надёжность — мы всегда выполняем взятые на себя обязательства; прозрачность — честное ценообразование без скрытых платежей; клиентоориентированность — индивидуальный подход к потребностям каждого заказчика; профессионализм — наша команда состоит из опытных специалистов. </p></div><div class="text-block" data-v-6deca830><h3 data-v-6deca830>Наш автопарк и возможности</h3><p data-v-6deca830> Автопарк «ГрузЭкспресс» включает более 200 единиц техники, что позволяет нам подбирать оптимальный транспорт для любых задач: малотоннажные фургоны до 1,5 тонн для городских перевозок; среднетоннажные грузовики до 5 тонн для региональных маршрутов; большегрузные автомобили до 20 тонн для магистральных перевозок; рефрижераторы для транспортировки скоропортящихся продуктов; автомобили с гидробортом для работы в стеснённых условиях; специализированный транспорт для негабаритных грузов. </p><p data-v-6deca830> Вся техника регулярно проходит техническое обслуживание и оснащена системами спутникового мониторинга GPS/ГЛОНАСС, что позволяет отслеживать местоположение груза в режиме реального времени и контролировать соблюдения температурного режима при транспортировке грузов, требующих особых условий. </p></div><div class="text-block" data-v-6deca830><h3 data-v-6deca830>Наша команда</h3><p data-v-6deca830> Команда «ГрузЭкспресс» — это более 300 профессионалов, каждый из которых вносит свой вклад в общий успех. Наши водители имеют многолетний опыт работы и регулярное повышение квалификации. Логисты разрабатывают оптимальные маршруты, учитывая дорожную ситуацию, погодные условия и особенности груза. Менеджеры по работе с клиентами обеспечивают оперативное решение любых вопросов на всех этапах сотрудничества. Служба контроля качества постоянно анализирует показатели и внедряет улучшения в рабочие процессы. </p></div><div class="stats-section" data-v-6deca830><h2 class="section-title" style="text-align:center;margin-bottom:var(--spacing-2xl);" data-v-6deca830>Наши достижения в цифрах</h2><div class="about-stats" data-v-6deca830><div class="stat-item" data-v-6deca830><div class="stat-number" data-v-6deca830>13+</div><div class="stat-label" data-v-6deca830>Лет на рынке</div></div><div class="stat-item" data-v-6deca830><div class="stat-number" data-v-6deca830>50 000+</div><div class="stat-label" data-v-6deca830>Выполненных заказов</div></div><div class="stat-item" data-v-6deca830><div class="stat-number" data-v-6deca830>200+</div><div class="stat-label" data-v-6deca830>Единиц техники</div></div><div class="stat-item" data-v-6deca830><div class="stat-number" data-v-6deca830>300+</div><div class="stat-label" data-v-6deca830>Сотрудников</div></div><div class="stat-item" data-v-6deca830><div class="stat-number" data-v-6deca830>85</div><div class="stat-label" data-v-6deca830>Регионов доставки</div></div><div class="stat-item" data-v-6deca830><div class="stat-number" data-v-6deca830>98%</div><div class="stat-label" data-v-6deca830>Довольных клиентов</div></div></div></div>',5))])])]))}}),V=o(m,[["__scopeId","data-v-6deca830"]]);export{V as default};
